public void CalculateAllIn(ProductDescription pd, IList cashflow)
 {
 if (cashflow != null && !cashflow.Any()) { pd.AllIn = null; return; }

 var allInFeesTypes = new[] { CashflowType.PlatformFee, CashflowType.IntermediaryFee };
 var fees = cashflow.Where(cf => allInFeesTypes.Contains(cf.Type)).Sum(cf => cf.Total);

 // no platform or broker fees, no all in - nominal will be used
 if (fees == 0d) { pd.AllIn = null; return; }

 // fixed loans (non reference) -> adds all coupons
 // variable or reference based -> adds spread and liquidity costs
 var coupon = pd.InterestBaseRate == InterestBaseRate.None
 ? cashflow.Where(cf => cf.Type == CashflowType.Coupon).Sum(cf => cf.Total)
 : 0d;

 // unlimited, considers maturity of 1 year
 // otherwise, gets the years by summing all the interest years of the cashflow
 var years = pd.Maturity.IsUnlimited ? 1d : cashflow.Sum(cf => cf.InterestPeriodYears);
 var costs = pd.Spread ?? 0d + pd.LiquidityCosts ?? 0d;

 // we always store the all in as a percentage, conversion to bps in the
 // case of reference rate and variables happens in the FE
 pd.AllIn = costs + (fees + coupon) / (pd.Volume \* years) \* 100;
 }

